<?php namespace App\Http\Responses; use Illuminate\Http\JsonResponse; use Illuminate\Http\Response; class ApiResponse extends JsonResponse { public static function success($data = [], string $message = 'Success', int $code = Response::HTTP_OK): JsonResponse { return new static([ 'status' => 'success', 'message' => $message, 'data' => $data ], $code); } public static function error(string $message = 'Error', int $code = Response::HTTP_BAD_REQUEST, $errors = null): JsonResponse { return new static([ 'status' => 'error', 'message' => $message, 'errors' => $errors ], $code); } public static function validationError($errors, string $message = 'Validation failed'): JsonResponse { return self::error($message, Response::HTTP_UNPROCESSABLE_ENTITY, $errors); } public static function forbidden(string $message = 'Access denied'): JsonResponse { return self::error($message, Response::HTTP_FORBIDDEN); } public static function notFound(string $message = 'Resource not found'): JsonResponse { return self::error($message, Response::HTTP_NOT_FOUND); } }